const AddOrder  = ({ data,  confirm }) => {
	
	let flds = [
		"dl_number",
		"dl_issues",
		"dl_exire",
		"dl_type",
		"endorsment",
		"restriction",
		"documentType"
	]

	const frmNm = "logistic_order_new"

	const [initialize, setInitialize] = useState(false);
	const [loading, setloading] = useState(0);

	const [obs, set_obs] = useState(1);
	
	const updObs =  () => {
		set_obs(gen16CodeId())
	}


	
	useEffect(() => {
		if (!initialize) {
			
			setInitialize(true);
			set_obs(gen16CodeId());
			if(!getStore("print_structure")?.dl_trns_struct_print){
				// get_print_structure(updObs)
			}
			
			return () => {
				// updStore(frmNm, null);
			}; 
		}
	});

	const updFrm = (f, v) => {
		let frm2 = getStore(frmNm) || {};
		frm2[f] = v;
		updStore(frmNm, frm2);
		set_obs(gen16CodeId())
	};

	

	const save  = async ()  => {

		let ffm =  getStore(frmNm);

		let bdyq2 = {};
		if(ffm["order_lgs_Id"]){
			let diff = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )
			
			bdyq2 = {...getStore(qryStore())?.upd_logistic_order};
			bdyq2.params = {
				
        		businessId:  getStore("profileUser")?.businessId,
				customerId: getStore(qryKLogisticClient())?.clientNotaryId,
				"order_lgs_Id": ffm["order_lgs_Id"]
			};
			bdyq2.data2update = diff.data;
		}
		else{
			ffm["order_lgs_Id"] = gen16CodeId();
			
			if(!ffm["date"]){
				ffm["date"] = (new Date()).getTime()+800;
			}
			else{
				ffm["date"] =(new Date(ffm["date"])).getTime();
			}
			bdyq2 = {...getStore(qryStore())?.add_logistic_order};
			bdyq2.params = {
        		businessId:  getStore("profileUser")?.businessId,
				customerId: getStore(qryKLogisticClient())?.clientNotaryId
			};
			bdyq2.form = ffm;
		}

		fetchServer(bdyq2)


	}

	const fetchServer  = async (bdyq2)  => {
		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		if (td && !td.error) {
			close();
		}
	}





	const print  = async ()  => {

		let user = {...getStore(qryKLogisticClient())};
		let ffm = Object.assign({}, getStore(frmNm),user);

		let fullname =	txtOrempty(user?.firstName) + txtOrempty(user?.middleName) +  txtOrempty(user?.lastName);
		
		if(user?.firstName){
			ffm["name_jury"] = fullname;
			ffm["name"] = fullname;
		}

		if(user["dateOfBirth"]){
			ffm["dob_p"] = parseDateMMDDYYYY(user["dateOfBirth"]);
		}

		if(ffm["dl_issues"]){
			ffm["dl_issue_p"] = parseDateMMYYYY(ffm["dl_issues"]);
		}

		if(ffm["dl_exire"]){
			ffm["dl_exp_p"] = parseDateMMYYYY(ffm["dl_exire"]);
		}

		if(ffm["ss"]){
			ffm["SS"] = parseSS(ffm["ss"]);
		}else{
			ffm["SS"] = "N/A";
		}

		
	
		
		let tDdate = ffm["translateDate"] ? (new Date(ffm["translateDate"]))  : (new Date());

		let DD = tDdate.getDate();
		let YY = tDdate.getFullYear().toString().slice(2,4);



		ffm["inter_date"] =  parseDateMMDDYYYY(tDdate.getTime());



		ffm["day_en_jury"] = DD;
		ffm["day_es_jury"] = DD;
		ffm["half_year_en_jury"] = YY;
		ffm["half_year_es_jury"] = YY;

		let MM = tDdate.getMonth()+1;

		ffm["month_en_jury"] = _monthNames["en"][MM];
		ffm["month_es_jury"] = _monthNames["es"][MM];
		
	
		//let pdfUri = await generateTranslateDriverLicense(ffm, true, true);
		//window.open(pdfUri);
	};

	const close  = ()  => {
		data?.modalID && CloseModal({id:data?.modalID});
	}
	
	let validSv = compareJSON(flds,getStore(frmNm),getStore(frmNm + "_bck") )
	

	let beneficiaryId = getStore(frmNm).beneficiaryId;
	let clientItm = getStore(qryKLogisticClient());
	let receiverItm = getStore("beneficiaries_ids")?.[beneficiaryId];

	const addBulto =  (v, obj) => {
		setloading(true);
		let ffm = {...getStore(frmNm)};
		if(!ffm.packages){
			ffm.packages={};
		}
		ffm.packages[v] = obj;
		updStore(frmNm, ffm);
		setTimeout(() => {
			setloading(false);
		}, 200);
		
	}

	const rmvBulto =  (v) => {
		setloading(true);
		let ffm = {...getStore(frmNm)};
		if(!ffm.packages){
			ffm.packages={};
		}
		delete ffm.packages[v];
		updStore(frmNm, ffm);
		setTimeout(() => {
			setloading(false);
		}, 200);
		
	}

	
	return(
		<div 
			className={"order_pack"}
			style={{
				maxHeight: "80vh",
				width: "820px",
				overflow: "auto",
				background: "var(--dark-800)",
				borderRadius: 13,
				padding: "10px 19px"
			}}
		>
			<div className="_dsplFlx ">
				<p className="form_title">
					Nueva Orden
				</p>
				<div className="flexSpace"/>
				<div style={{margin:"16px 16px 0 0"}}>
						<GrayButton label={"Save"} clickHandler={save}/>
					
				</div>
			</div>
			
			

			<div className="_dsplFlx " style={{margin:"36px 6px 0 0"}}>
				<div>
					<div className="lbl_h23"  style={{textAlign: "left", padding: 6}}>
						Envia: 
					</div>
					<LabelText
						label={"Nombre: "}
						value={txtOrempty(clientItm?.firstName) + txtOrempty(clientItm?.middleName)  + txtOrempty(clientItm?.lastName)}
					/>
					<LabelText
						label={"Telefono: "}
						value={clientItm?.phoneNumber }
					/>
					<LabelText
						label={"Ciudad: "}
						value={clientItm?.currentLocation?.city }
					/>
					<LabelText
						label={"Estado: "}
						value={clientItm?.currentLocation?.state }
					/>
					<LabelText
						label={"Pais: "}
						value={clientItm?.currentLocation?.country }
					/>
				</div>
				<div className="flexSpace"/>
				<div>
					<div className="lbl_h23"  style={{textAlign: "left", padding: 6}}>
						Recibe: 
					</div>
					<LabelText
						label={"Nombre: "}
						value={txtOrempty(receiverItm?.firstName) + txtOrempty(receiverItm?.middleName)  + txtOrempty(receiverItm?.lastName)}
					/>
					<LabelText
						label={"Telefono: "}
						value={receiverItm?.phoneNumber }
					/>
					<LabelText
						label={"Ciudad: "}
						value={receiverItm?.currentLocation?.city }
					/>
					<LabelText
						label={"Estado: "}
						value={receiverItm?.currentLocation?.state }
					/>
					<LabelText
						label={"Pais: "}
						value={receiverItm?.currentLocation?.country }
					/>
				</div>
			</div>
			
			<div className="separator"/>

			{loading?
			<div className="_dsplFlx ">
				<div className="flexSpace"/>
				<div className="icon_compr _dsplFlx" style={{marginTop:10, height: 75, maxWidth: 140}}>
					<div className="lbl_saving ">
							Addding ... 
					</div>
					<LoadingColorSpinner stroke={"var(--primary-blue--backg-30)"} size={24} strokeW={8}/>
				</div>
				<div className="flexSpace"/>
			</div>:
			<div style={{marginBottom:32}} >
				<AddPackage  
					addBulto={addBulto}
					
				/>
			</div>
			}
			




			<div className="_dsplFlx hdr_bar blue30">
				<div className="tr_bar_20">
					Id
				</div>
				<div className="tr_bar_50">
					Tipo de Bulto
				</div>
				<div className="tr_bar_25">
					Peso (Lb)
				</div>
				<div className="tr_bar_5">
					
				</div>
			</div>


			{getStore(frmNm)?.["packages"] && ObjectKeys(getStore(frmNm)?.["packages"]).map(pckId=>{
				let pckItm = getStore(frmNm)?.["packages"]?.[pckId];
				return (
					<ItemPackage pckItm={pckItm} remove={rmvBulto}/>
				)
			})}





			<div className="_dsplFlx spaceAround" style={{marginTop:20}}>
		
			{validSv?.hasChange ? (
				<div className="_dsplFlx ">
					<div className="flexSpace"/>
					<div className="card">
						<GrayButton label={"Actualizar"} clickHandler={save}/>
						
					</div>
				</div>
			):<div className="card"/>}

			</div>
		</div>
	)

}



export default AddOrder;






const ItemPackage  = ({ pckItm, remove }) => {
	
	const rmv = () =>{
		remove(pckItm?.packageId)
	}
	
	return (
		<div className="_dsplFlx hdr_bar">
			<div className="tr_bar_20">
				{pckItm?.packageId}
			</div>
			<div className="tr_bar_50">
				{pckItm?.serviceType?.label}
			</div>
			<div className="tr_bar_25">
				{pckItm?.weight}
			</div>
			<div className="tr_bar_5">
				<div onClick={rmv} className="icon_delete">
					<Svg 
						name={"outline_delete"} 
						color={"var(--light-300)"}
					/>
				</div>
			</div>
		</div>
	)
}



const AddPackage  = ({ addBulto }) => {
	const [weight, setWeight] = useState(0);
	const [serviceType, setServiceType] = useState({});


	const add = () =>{
		let packageId = gen4NumCode();
		addBulto(packageId,{
			weight,
			serviceType,
			packageId
		})
	}
	
	return (
		<div className="_dsplFlx spaceAround flxWrp" style={{margin:"10px 0px 20px 0"}}>
				<div className="flexSpace"/>
				<div style={{marginTop:32, minWidth: 290}} >
					<DropDwnPicker 
						init={serviceType?.["id"]}
						lbl_empty={serviceType?.["label"] || "Tipo de Envio"} 
						list={[
							{label: "Aerovaradero (45 dias)", id:"AV1X"},
							{label: "Expedita Maritimo (90 dias)", id:"EX2MA"},
							{label: "Personal (12 dias)", id:"MLOH"},
						]}
						onSelect={setServiceType} 
						background={"var(--dark-900)"}
						color={"var(--light-200)"}
					/>
				</div>
				<div className="flexSpace"/>
				<TextInput  init={weight} 
					label={"Peso del Bulto"} 
					width={160} updChanges={setWeight}
				/>
				<div className="flexSpace"/>
				<div style={{margin:"32px 0px 0 0"}}>
					<GrayButton label={"Agregar Bulto"} clickHandler={add}/>
				</div>
				<div className="flexSpace"/>
			</div>
	)
}





const GrayButton  = ({ clickHandler, label }) => {
	return (
		<div className=" jaqJnq_hrm1"  >
			<button className="gHAsFI_hrm1 dqnOfN jUrKkb" onClick={clickHandler}>
				<span className=" jaqJnq_hrm1" >
					{label}
				</span>
			</button>
		</div>
	)
}



const parseSS = (v) =>{
	if(v){
		let f = v.substring(0,3) + " - "+ v.substring(3,5) + " - "+v.substring(5,9);
		return f;
	}
	return ""

}







const LabelText = ({label, value}) =>{

	const copyToClpb  =  (v)  => {
		// copyToClipboard(v);
	};

	if(!value){
		return null;
	}
	return (
		<div className="_dsplFlx dtls">
			<div className="lbl_h_dtls">
				{label}
			</div>
			<div className="lbl_dtls" onClick={()=>copyToClpb(value)}>
				{value}
			</div>
		</div>
	) 
}

