const PickPerson  = ({ init, emptyLabel, onSelect }) => {

	const [list, setList] = useState([]);

	const parseD =  (v) => {
		let nA = []
		v && ObjectKeys(v).map(cl=>{
			if(v[cl]?.countryId==="CUB"){
				let fullNm = txtOrempty(v[cl]?.firstName) + txtOrempty(v[cl]?.middleName)  + txtOrempty(v[cl]?.lastName);
				nA.push({id:cl, label: fullNm });
			}
		})
		setList(nA);
	}

	const fetch =  (v) => {
		search_customer_logistic_cl(v, parseD);
	}

	const clear =  () => {
		setList([]);
	}



	return (
		<div style={{minWidth: 260}}>
			<DropDwnSearchPicker
				lbl_empty={init || emptyLabel} 
				list={list}
				onSelect={(e)=>onSelect(e)} 
				background={"var(--dark-900)"}
				color={"var(--light-200)"}
				callempty={clear}
				fetchData={fetch}
			/>
		</div>
	)

}



const FamilyDashboardView  = ({ tabs, active, updTab }) => {
	const [obs, set_obs] = useState(1);
	
	const updObs =  () => {
		set_obs(gen16CodeId())
	}

	const handled =  (td) => {
		if(td.beneficiariesInfo){
			updStore("beneficiaries_ids", convertArray2Obj(td.beneficiariesInfo, "customerLogisticId"));
		}
		updStore(qryKLogisticClient(), td);
		updStore(qryKLogisticClient()+"_bck", JSON.parse(JSON.stringify(td)));
	
		updObs();
	}
	
	const save =  async(v) => {
		
		let cId = getStore(qryKLogisticClient())?.["customerLogisticId"];
		let bdyq2 = {...getStore(qryStore())?.upd_customer_logistic};
		bdyq2.params = {
			"customerLogisticId": cId,
			businessId:  getStore("profileUser")?.businessId
		}
		
		bdyq2.data2update = v;	

		const res = fetchEncryptStream(bdyq2);
		const td = await res;
		
		if (td && !td.error) {
			getById_logisticClient(cId,handled);
		}

	}

	const addBeneficiaries =  (v) => {
		let beneficiaries = getStore(qryKLogisticClient())?.beneficiaries || {};
		if(Array.isArray(getStore(qryKLogisticClient())?.beneficiaries)){
			beneficiaries ={};
		}
		beneficiaries[v] = 1;
		let d2u = {beneficiaries};
		save(d2u);
	}

	const rmvBeneficiaries =  (v) => {
		let beneficiaries = getStore(qryKLogisticClient())?.beneficiaries || {};
		delete beneficiaries[v];
		let d2u = {beneficiaries};
		save(d2u);
		window.scrollTo(0,0);
	}
	
	

	let clientItm = getStore(qryKLogisticClient());

	



	return (
		<div>
			<div style={{paddingTop: 30}}/>

			<div className="_dsplFlx " >
				<div className="iMTYiw" style={{marginTop: "8px"}}>
				Beneficiarios 
				</div>
				<div className="flexSpace"/>
				<AddChild
					title={"Agregar"}
					updKey={addBeneficiaries}
				/>
				
			</div>

			<div style={{paddingTop: 30}}/>
			
			
			
			{clientItm?.beneficiariesInfo?.map(chl=>{
				return (
					<ItemChildView 
						key={"kid" + chl.customerLogisticId}
						item={chl}
						fld={"kid"}
						updKey={rmvBeneficiaries}
					/>
				)
			})}
			


			



		</div>
          
	)
}


const AddChild  = ({updKey, title }) => {

	const [show, setShow] = useState(false);

	const select  =  (e)  => {
		updKey(e.id);
		setShow(false);
	};

	return (
		<div className="_dsplFlx " >
			<div className="flexSpace"/>
			{show ?
			<div className="client_item_box gWXAaj jlytmu">
				<div className="_dsplFlx " >
				
					<div className="_dsplFlx dtls header_card">
						<div className="lbl_h_dtls">
							{title} 
						</div>
						
					</div>
					<div className="flexSpace"/>
					<PickPerson
						onSelect={select}
					/>
				</div>	
			</div>	
			:		
			<div className="iSTOvb kvXcCL"  style={{padding: "0 9px" , width: "160px"}}  onClick={()=>setShow(!show)}>
				{title}
			</div>
			}
		</div>

	)

}









export default FamilyDashboardView;












const ItemChildView  = ({ item,  updKey }) => {


	
	const copyToClpb  =  (v)  => {

		copyToClipboard(v);
	};

	const [obs, set_obs] = useState(1);
	
	const updObs =  () => {
		set_obs(gen16CodeId())
	}



	

	const rmv  =  (v)  => {

		let lastTimeCallModal = getStore("lastTimeCallModal") || 0;
		if(Date.now() > lastTimeCallModal){
			updStore("lastTimeCallModal", Date.now()+320);
			
			let modaldata = {};
			modaldata["zIndex"] = 450;
			modaldata["height"] = "40vh";
			// data['observeResize']=true;
			modaldata["props"] = { minHeight: "1vh", overlay: true, closeEvent: ()=>{}  };
			modaldata["content"] = <DeleteAlert
				confirm={()=>updKey(item?.customerLogisticId)}
				lbl_p={"Eliminar"} 
				lbl_span={"Se eliminara la referencia puede asociarlo nuevamente cuando quiera"}
			/>
			OpenModal(modaldata);
		}
	}
	


	const addNewOrder =  (v) => {
		let clientItm = getStore(qryKLogisticClient());
		let newOrd = {
			"senderId": clientItm?.customerLogisticId,
			"beneficiaryId": item?.customerLogisticId
		};
		
		updStore("logistic_order_beneficiary", item);
		updStore("logistic_order_new", newOrd);
		
		let dataModal = {};
		dataModal["zIndex"] = 480;
		// data['observeResize']=true;
		dataModal["props"] = { minHeight: "1vh", overlay: true };
		dataModal["content"] = <AddOrder  confirm={updObs} />
		OpenModal(dataModal);
	}



	return (


		
	<div className="client_item_box gWXAaj jlytmu" style={{marginBottom: 14}}>
		<div className="_dsplFlx ">

		<div className="_dsplFlx dtls header_card">
				<div className="lbl_h_dtls">
					Full Name: 
				</div>
				<div className="lbl_dtls" onClick={()=>copyToClpb(txtOrempty(item?.firstName) + txtOrempty(item?.middleName)  + txtOrempty(item?.lastName))}>
					{txtOrempty(item?.firstName) + txtOrempty(item?.middleName)  + txtOrempty(item?.lastName)}
				</div>
			</div>
			
			<div className="flexSpace"/>
			<div onClick={addNewOrder} style={{marginRight:15}}>
				<Svg 
					name={"open_package_file_outline"} 
					color={"var(--light-300)"}
				/>
			</div>
			<div onClick={rmv}>
				<Svg 
					name={"outline_delete"} 
					color={"var(--light-300)"}
				/>
			</div>
			
		</div>
		
		
		<ItemInfoView item={item}/>
	</div>

	)
}














